class Solution {
public:
    vector<long long> unmarkedSumArray(vector<int>& nums, vector<vector<int>>& queries) {
        int n = nums.size();
        vector<long long> answer;
        vector<bool> marked(n, false);
        long long sum = 0;
        for (int num : nums) sum += num;

        for (auto& query : queries) {
            int index = query[0], k = query[1];
            if (!marked[index]) {
                marked[index] = true;
                sum -= nums[index];
            }

            vector<pair<int, int>> unmarked;
            for (int i = 0; i < n; i++) {
                if (!marked[i]) unmarked.emplace_back(nums[i], i);
            }
            sort(unmarked.begin(), unmarked.end());

            for (int i = 0; i < min(k, (int)unmarked.size()); i++) {
                marked[unmarked[i].second] = true;
                sum -= unmarked[i].first;
            }
            answer.push_back(sum);
        }
        return answer;
    }
};
